// ============================================
// SET TEST DATA
// Provides hardcoded test input for the POC
// ============================================

return {
  json: {
    scene_audios: [
      { scene: 'hook',     duration: 2.5,  audio_url: null },
      { scene: 'solution', duration: 8.0,  audio_url: 'https://res.cloudinary.com/dtpqxuwby/video/upload/v1760562362/Alex_MakeMusic_-_I_Am_Good_tmyztb.mp3' },
      { scene: 'cta',      duration: 3.0,  audio_url: 'https://res.cloudinary.com/dtpqxuwby/video/upload/v1760562362/Alex_MakeMusic_-_I_Am_Good_tmyztb.mp3' }
    ],
    scene_avatars: [
      { scene: 'solution', video_url: 'https://res.cloudinary.com/dtpqxuwby/video/upload/v1774484701/kelly-avatar-preview_ngqdwl.mp4', mask_url: 'https://res.cloudinary.com/dtpqxuwby/video/upload/v1774484702/kelly-avatar-alpha-preview_x3z4vs.mp4' },
      { scene: 'cta',      video_url: 'https://res.cloudinary.com/dtpqxuwby/video/upload/v1774484701/kelly-avatar-preview_ngqdwl.mp4', mask_url: 'https://res.cloudinary.com/dtpqxuwby/video/upload/v1774484702/kelly-avatar-alpha-preview_x3z4vs.mp4' }
    ],
